def f(n: int) -> int:
    """Return the number of prime numbers strictly less than n (n ≤ 10000)."""
    if n <= 2:
        return 0

    # Sieve of Eratosthenes up to n-1
    limit = n - 1
    is_prime = [True] * (limit + 1)
    is_prime[0:2] = [False, False]  # 0 and 1 are not prime

    for p in range(2, int(limit**0.5) + 1):
        if is_prime[p]:
            step = p
            start = p * p
            is_prime[start:limit + 1:step] = [False] * ((limit - start) // step + 1)

    return sum(is_prime)
