def f(expr: str) -> int:
    i, n = 0, len(expr)

    def skip_spaces():
        nonlocal i
        while i < n and expr[i] == ' ':
            i += 1

    def peek() -> str:
        skip_spaces()
        return expr[i] if i < n else ''

    def consume() -> str:
        skip_spaces()
        ch = expr[i]
        i += 1
        return ch

    def parse_number() -> int:
        nonlocal i
        skip_spaces()
        start = i
        while i < n and expr[i].isdigit():
            i += 1
        return int(expr[start:i])

    def parse_factor() -> int:
        if peek() == '(':
            consume()                     # '('
            val = parse_expr()
            if peek() == ')':
                consume()                 # ')'
            return val
        return parse_number()

    def parse_term() -> int:
        val = parse_factor()
        while peek() == '*':
            consume()                     # '*'
            val *= parse_factor()
        return val

    def parse_expr() -> int:
        val = parse_term()
        while True:
            op = peek()
            if op == '+':
                consume()
                val += parse_term()
            elif op == '-':
                consume()
                val -= parse_term()
            else:
                break
        return val

    return parse_expr()
